import React, { useState, useEffect } from 'react';
import { getAllLocations, getSeatsByLocation, createSeat, updateSeat, deleteSeat, createLocation, deleteLocation } from '../../api/api';
import toast from 'react-hot-toast';

const AdminSeatsPage = () => {
  const [locations, setLocations] = useState([]);
  const [seats, setSeats] = useState([]);
  const [selectedLoc, setSelectedLoc] = useState(null);
  const [loading, setLoading] = useState(true);
  const [seatModal, setSeatModal] = useState(false);
  const [locModal, setLocModal] = useState(false);
  const [editSeat, setEditSeat] = useState(null);
  const [saving, setSaving] = useState(false);
  const [seatForm, setSeatForm] = useState({ seatNo:'', rowLetter:'A', seatType:'REGULAR', basePrice:'' });
  const [locForm, setLocForm] = useState({ locName:'', address:'', totalSeats:'', facilities:'' });

  const loadLocations = async () => {
    try {
      const res = await getAllLocations();
      const locs = res.data.data || [];
      setLocations(locs);
      if (locs.length > 0 && !selectedLoc) setSelectedLoc(locs[0]);
    } catch { toast.error('Failed to load locations'); }
    finally { setLoading(false); }
  };

  const loadSeats = async (locId) => {
    try {
      const res = await getSeatsByLocation(locId);
      setSeats(res.data.data || []);
    } catch { setSeats([]); }
  };

  useEffect(() => { loadLocations(); }, []);
  useEffect(() => { if (selectedLoc) loadSeats(selectedLoc.locationId); }, [selectedLoc]);

  const openCreateSeat = () => { setSeatForm({ seatNo:'', rowLetter:'A', seatType:'REGULAR', basePrice:'' }); setEditSeat(null); setSeatModal(true); };
  const openEditSeat = (s) => { setSeatForm({ seatNo:s.seatNo||'', rowLetter:s.rowLetter||'A', seatType:s.seatType||'REGULAR', basePrice:s.basePrice||'' }); setEditSeat(s); setSeatModal(true); };

  const saveSeat = async () => {
    if (!seatForm.seatNo || !seatForm.basePrice) { toast.error('Seat number and price required'); return; }
    setSaving(true);
    try {
      if (editSeat) { await updateSeat(editSeat.seatId, seatForm); toast.success('Seat updated'); }
      else { await createSeat(selectedLoc.locationId, seatForm); toast.success('Seat created'); }
      setSeatModal(false);
      loadSeats(selectedLoc.locationId);
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
    finally { setSaving(false); }
  };

  const delSeat = async (id) => {
    if (!window.confirm('Delete this seat?')) return;
    try { await deleteSeat(id); toast.success('Seat deleted'); loadSeats(selectedLoc.locationId); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const saveLocation = async () => {
    if (!locForm.locName || !locForm.address) { toast.error('Name and address required'); return; }
    setSaving(true);
    try {
      await createLocation({ ...locForm, totalSeats: parseInt(locForm.totalSeats) || 0 });
      toast.success('Venue created');
      setLocModal(false);
      setLocForm({ locName:'', address:'', totalSeats:'', facilities:'' });
      loadLocations();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
    finally { setSaving(false); }
  };

  const delLocation = async (id) => {
    if (!window.confirm('Delete this venue? All seats will be removed.')) return;
    try { await deleteLocation(id); toast.success('Venue deleted'); setSelectedLoc(null); loadLocations(); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const SEAT_TYPE_COLOR = { VIP:'var(--gold)', PREMIUM:'var(--blue)', REGULAR:'var(--text-secondary)' };
  const rows = {};
  seats.forEach(s => { const r = s.rowLetter||'A'; if (!rows[r]) rows[r]=[]; rows[r].push(s); });

  return (
    <div className="container page-content" style={{ background:'var(--bg-secondary)', minHeight:'100vh', paddingLeft:'28px', paddingRight:'28px' }}>
      <div className="page-header" style={{ display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'12px' }}>
        <div>
          <h1 className="page-title">SEAT MANAGEMENT</h1>
          <p className="page-subtitle">Manage venues and seat layouts</p>
        </div>
        <div style={{ display:'flex', gap:'10px' }}>
          <button onClick={() => setLocModal(true)} className="btn btn-secondary">➕ Add Venue</button>
          {selectedLoc && <button onClick={openCreateSeat} className="btn btn-primary">💺 Add Seat</button>}
        </div>
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'260px 1fr', gap:'24px', alignItems:'flex-start' }}>
        {/* Locations sidebar */}
        <div>
          <div style={{ fontSize:'11px', fontWeight:700, letterSpacing:'1px', textTransform:'uppercase', color:'var(--text-muted)', marginBottom:'10px' }}>Venues</div>
          <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
            {loading ? <div className="loading-center" style={{ padding:'20px' }}><div className="spinner" /></div> : locations.map(l => (
              <div key={l.locationId}
                onClick={() => setSelectedLoc(l)}
                className="card"
                style={{
                  padding:'12px 14px', cursor:'pointer',
                  borderColor: selectedLoc?.locationId === l.locationId ? 'var(--accent)' : 'var(--border)',
                  background: selectedLoc?.locationId === l.locationId ? 'var(--accent-dim)' : 'var(--bg-card)',
                  transition:'var(--transition)',
                }}>
                <div style={{ fontWeight:600, fontSize:'13px', color: selectedLoc?.locationId === l.locationId ? 'var(--accent)' : 'var(--text-primary)' }}>{l.locName}</div>
                <div style={{ fontSize:'11px', color:'var(--text-muted)', marginTop:'2px' }}>{l.address}</div>
                <div style={{ fontSize:'11px', color:'var(--text-muted)' }}>Capacity: {l.totalSeats}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Seat layout */}
        <div>
          {!selectedLoc ? (
            <div className="empty-state"><div className="empty-state-icon">📍</div><h3>Select a Venue</h3></div>
          ) : (
            <>
              <div className="card" style={{ padding:'16px 20px', marginBottom:'20px', display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'12px' }}>
                <div>
                  <div style={{ fontFamily:'var(--font-display)', fontSize:'1.3rem', letterSpacing:'1px' }}>{selectedLoc.locName}</div>
                  <div style={{ fontSize:'13px', color:'var(--text-secondary)' }}>📍 {selectedLoc.address} &nbsp;·&nbsp; {seats.length} seats configured</div>
                  {selectedLoc.facilities && <div style={{ fontSize:'12px', color:'var(--text-muted)', marginTop:'2px' }}>✨ {selectedLoc.facilities}</div>}
                </div>
                <button onClick={() => delLocation(selectedLoc.locationId)} className="btn btn-danger btn-sm">Delete Venue</button>
              </div>

              {/* Legend */}
              <div style={{ display:'flex', gap:'20px', marginBottom:'16px', flexWrap:'wrap' }}>
                {Object.entries(SEAT_TYPE_COLOR).map(([type, color]) => (
                  <span key={type} style={{ fontSize:'12px', color, display:'flex', alignItems:'center', gap:'6px' }}>
                    <span style={{ width:16, height:16, background:`${color}22`, border:`2px solid ${color}`, borderRadius:'3px', display:'inline-block' }} />{type}
                  </span>
                ))}
              </div>

              {seats.length === 0 ? (
                <div className="empty-state">
                  <div className="empty-state-icon">💺</div>
                  <h3>No Seats Added</h3>
                  <p style={{ fontSize:'13px' }}>Add seats to this venue</p>
                  <button onClick={openCreateSeat} className="btn btn-primary" style={{ marginTop:'16px' }}>Add Seat</button>
                </div>
              ) : (
                <div className="card" style={{ padding:'24px', overflowX:'auto' }}>
                  {Object.entries(rows).sort().map(([row, rowSeats]) => (
                    <div key={row} style={{ display:'flex', gap:'6px', alignItems:'center', marginBottom:'8px' }}>
                      <span style={{ width:'20px', fontSize:'12px', color:'var(--text-muted)', fontFamily:'var(--font-mono)', textAlign:'center', flexShrink:0 }}>{row}</span>
                      {rowSeats.sort((a,b)=>a.seatNo-b.seatNo).map(s => {
                        const c = SEAT_TYPE_COLOR[s.seatType]||'var(--text-muted)';
                        return (
                          <div key={s.seatId} style={{ position:'relative', group:'true' }}>
                            <button
                              title={`${s.rowLetter}${s.seatNo} | ${s.seatType} | ₹${s.basePrice}`}
                              onClick={() => openEditSeat(s)}
                              style={{
                                width:'36px', height:'32px',
                                borderRadius:'5px 5px 2px 2px',
                                border:`2px solid ${c}`,
                                background:`${c}15`,
                                color:c, fontSize:'10px', fontWeight:600,
                                cursor:'pointer', transition:'var(--transition)',
                                fontFamily:'var(--font-mono)',
                              }}
                              onMouseEnter={e => e.currentTarget.style.background=`${c}35`}
                              onMouseLeave={e => e.currentTarget.style.background=`${c}15`}
                            >{s.seatNo}</button>
                          </div>
                        );
                      })}
                    </div>
                  ))}
                </div>
              )}

              {/* Seat Table */}
              {seats.length > 0 && (
                <div className="table-wrap" style={{ marginTop:'20px' }}>
                  <table>
                    <thead><tr><th>Seat</th><th>Row</th><th>Type</th><th>Base Price</th><th>Actions</th></tr></thead>
                    <tbody>
                      {seats.sort((a,b)=>(a.rowLetter+a.seatNo).localeCompare(b.rowLetter+b.seatNo)).map(s => (
                        <tr key={s.seatId}>
                          <td style={{ fontFamily:'var(--font-mono)', fontWeight:600 }}>{s.rowLetter}{s.seatNo}</td>
                          <td>{s.rowLetter}</td>
                          <td><span style={{ color:SEAT_TYPE_COLOR[s.seatType], fontSize:'12px', fontWeight:600 }}>{s.seatType}</span></td>
                          <td>₹{parseFloat(s.basePrice).toFixed(2)}</td>
                          <td>
                            <div style={{ display:'flex', gap:'6px' }}>
                              <button onClick={() => openEditSeat(s)} className="btn btn-secondary btn-sm">Edit</button>
                              <button onClick={() => delSeat(s.seatId)} className="btn btn-danger btn-sm">Del</button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* Seat Modal */}
      {seatModal && (
        <div className="modal-overlay" onClick={() => setSeatModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editSeat ? 'EDIT SEAT' : 'ADD SEAT'}</h3>
              <button className="modal-close" onClick={() => setSeatModal(false)}>✕</button>
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'12px' }}>
              <div className="form-group">
                <label className="form-label">Seat Number *</label>
                <input className="form-input" value={seatForm.seatNo} onChange={e=>setSeatForm(f=>({...f,seatNo:e.target.value}))} placeholder="1, 2, 3..." />
              </div>
              <div className="form-group">
                <label className="form-label">Row Letter *</label>
                <input className="form-input" value={seatForm.rowLetter} onChange={e=>setSeatForm(f=>({...f,rowLetter:e.target.value.toUpperCase().charAt(0)||'A'}))} placeholder="A, B, C..." maxLength={1} />
              </div>
              <div className="form-group">
                <label className="form-label">Seat Type</label>
                <select className="form-input" value={seatForm.seatType} onChange={e=>setSeatForm(f=>({...f,seatType:e.target.value}))}>
                  <option value="REGULAR">REGULAR</option>
                  <option value="PREMIUM">PREMIUM</option>
                  <option value="VIP">VIP</option>
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Base Price (₹) *</label>
                <input type="number" className="form-input" value={seatForm.basePrice} onChange={e=>setSeatForm(f=>({...f,basePrice:e.target.value}))} placeholder="150" />
              </div>
            </div>
            <div style={{ display:'flex', gap:'12px' }}>
              <button onClick={() => setSeatModal(false)} className="btn btn-secondary" style={{ flex:1 }}>Cancel</button>
              <button onClick={saveSeat} disabled={saving} className="btn btn-primary" style={{ flex:2 }}>
                {saving ? 'Saving...' : editSeat ? 'Update Seat' : 'Add Seat'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Location Modal */}
      {locModal && (
        <div className="modal-overlay" onClick={() => setLocModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">ADD VENUE</h3>
              <button className="modal-close" onClick={() => setLocModal(false)}>✕</button>
            </div>
            <div className="form-group">
              <label className="form-label">Venue Name *</label>
              <input className="form-input" value={locForm.locName} onChange={e=>setLocForm(f=>({...f,locName:e.target.value}))} placeholder="PVR Cinemas, Chennai" />
            </div>
            <div className="form-group">
              <label className="form-label">Address *</label>
              <input className="form-input" value={locForm.address} onChange={e=>setLocForm(f=>({...f,address:e.target.value}))} placeholder="Full address" />
            </div>
            <div className="form-group">
              <label className="form-label">Total Seating Capacity</label>
              <input type="number" className="form-input" value={locForm.totalSeats} onChange={e=>setLocForm(f=>({...f,totalSeats:e.target.value}))} placeholder="200" />
            </div>
            <div className="form-group">
              <label className="form-label">Facilities</label>
              <input className="form-input" value={locForm.facilities} onChange={e=>setLocForm(f=>({...f,facilities:e.target.value}))} placeholder="Parking, AC, Dolby, IMAX..." />
            </div>
            <div style={{ display:'flex', gap:'12px' }}>
              <button onClick={() => setLocModal(false)} className="btn btn-secondary" style={{ flex:1 }}>Cancel</button>
              <button onClick={saveLocation} disabled={saving} className="btn btn-primary" style={{ flex:2 }}>
                {saving ? 'Saving...' : 'Create Venue'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminSeatsPage;
